     {
         _registry.Register<ILogger>(new FakeLogger());
         _registry.Register<IRepository>(new FakeRepository());

         _registry.Clear();

         Assert.AreEqual(0, _registry.GetAll().Count);
     }

     [TestMethod]
     public void Remove_RemovesSpecificService()
     {
         _registry.Register<ILogger>(new FakeLogger());
         _registry.Register<IRepository>(new FakeRepository());

         _registry.Remove<ILogger>();

         Assert.IsNull(_registry.Resolve<ILogger>());
         Assert.IsNotNull(_registry.Resolve<IRepository>());
     }

     private interface ILogger { }
     private interface IRepository { }
     private sealed class FakeLogger : ILogger { }
     private sealed class FakeRepository : IRepository { }
 }
